window.__QUIZ_DATA__=[{"id":"theory>Biology>2001>PART I>1>a>i","subject":"Biology","year":"2001","type":"Theory","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Draw and label the human sperm cell","images":["data:image/png;base64,"],"marking_scheme":"Note: - Head must be oval  - middle piece must be very short  - Tail long and whip-like","marks":"7","difficulty":"2"},{"id":"theory>Biology>2001>PART I>1>a>ii","subject":"Biology","year":"2001","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"State where the sperm cell is produced and where it is stored.","images":[],"marking_scheme":"Site of :  * production - Testis  * Storage - Epididymis(Temporarily)","marks":"3","difficulty":"1"},{"id":"theory>Biology>2001>PART I>1>b","subject":"Biology","year":"2001","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Explain how the structure of the sperm cell enables it to function effectively in fertilization","images":[],"marking_scheme":"Structure and function of sperm cell.  - Acrosome: found in the head region contains lytic enzyme used to dissolve egg membrane or penetrate the egg during fertilisation.  - Middle piece - contains numerous mitochondia which generate energy used by sperm to swim towards egg  - long whip-like tail or flagellum is to propel or move the sperm cell  - The nucleus in the head of sperm contains genetic material which fuses with nucleus of the egg/ovum","marks":"4","difficulty":"3"},{"id":"theory>Biology>2001>PART I>1>c","subject":"Biology","year":"2001","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Mention four advantages of sexual reproduction","images":[],"marking_scheme":"- Permit variability of individuals   - Enhance survival in new or changing environment  - Allow the production of hybrid for desirable traits.  - Provides means for maintenance of chromosome number from generation to generation","marks":"4","difficulty":"2"},{"id":"theory>Biology>2001>PART I>2>a>i","subject":"Biology","year":"2001","type":"Theory","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"Draw and label the mammalian heart","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"10","difficulty":"2"},{"id":"theory>Biology>2001>PART I>2>a>ii","subject":"Biology","year":"2001","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"Explain briefly pulmonary circulation in mammals","images":[],"marking_scheme":"- Heart muscles contract, deoxygenerated blood from right ventricle passes through the pulmonary value pulmonary artery  - Then to lung capillaries for exchange of oxygen and carbondioxide  - oxygenated blood from the lungs then returns to the left auricle via the pulmonary vein","marks":"3","difficulty":"2"},{"id":"theory>Biology>2001>PART I>2>b","subject":"Biology","year":"2001","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)","question":"State five processes by which the mammalian body reduces it temperature","images":[],"marking_scheme":"- Relaxation of hair erector muscles   - Reduction of the body's metabolic activity  - Vasodilation occurs.  - Increased sweat production  - Reduction in heat generated by muscles.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2001>PART I>3>a","subject":"Biology","year":"2001","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE","question":"State eight human activities that may pollute water bodies","images":[],"marking_scheme":"- Dumping of household refuse into water  - oil spillage  - use of dynamites or explosive for fishing  - Dumping of dyes from testile factories into water  - Thermal pollution from industrial plants  - Use of chemical in fishing  - Dumping of agrochemicals or washing into water body  - Pouring detergent from hoes or factories into water","marks":"5","difficulty":"2"},{"id":"theory>Biology>2001>PART I>3>b","subject":"Biology","year":"2001","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"Explain the measures that may be used to prevent pollution of water bodies","images":[],"marking_scheme":"- Treat raw sewage before discharge into water or prohibitation of human waste disposal into water   - Refuse must be burnt or buried not discharged into water  - Limit the use of pesticide and fertilizers   - Recycle industrial waste before discharge   - Enforcement of safety laws to prevent pollution of water bodies   - Educating people on safe practices to reduces or stop pollution of water bodies","marks":"5","difficulty":"3"},{"id":"theory>Biology>2001>PART I>3>c","subject":"Biology","year":"2001","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"Mention four methods of purifying water","images":[],"marking_scheme":"-  Boiling   - Addition of chemicals e.g Alum or chlorination  - Distillation  - Sterilization e.g by using uv light  - Filteration.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2001>PART I>4>a>i","subject":"Biology","year":"2001","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM","question":"Define tropic and nastic movement","images":[],"marking_scheme":"- Tropic movement: is the growth movement of plants organs in response to external unilateral or directional stimulus  - Nastic movement: is a non-directional movement of plant or part of a plant in response to diffused stimulus","marks":"2","difficulty":"1"},{"id":"theory>Biology>2001>PART I>4>a>ii","subject":"Biology","year":"2001","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM","question":"List four differences between tropic and nastic movement","images":[],"marking_scheme":"Tropic movement Nastic movement1.movement is not easily reversible movement is reversible2. Response leads to growth Response does not lead to growth3. Movement are not due to cell turgor movement is due to cell turgor4. Response is towards the direction of stimulus Response is not directed towards the stimulus5. slow response Rapid response6. Response are not due to pressure  Response is due to pressure","marks":"4","difficulty":"2"},{"id":"theory>Biology>2001>PART I>4>b","subject":"Biology","year":"2001","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Describe an experiment to show that auxins are produced in the apical cell of a shoot","images":[],"marking_scheme":"Experiment to show auxins are produced in the apical cells of a shoot.  Material required : 3 spotted seedlings of maize labelled , A, B and C. Agar block, sharp knife /cutting instrument, mica sheet or aluminium foil or cover slip.  Method :  -cut the tip of the coleoptile soot in A to serve as control .  - Leave decpitated shoot for about 48 hours.  - Select another potted seedling B, and cut off tip of coleoptile/ shoot  - Place the cut tip on an agar block for about 2-6hours.  - Place Agar block on cut surface /stump of decapitated   - Select a third seedling C, and cut off the tip of the coleoptile  - place the tip of coleoptile on micca sheet for 2-6hours  - place mica sheet on cut surface of deapitated shoot and leave for about 48 hours   OBSERVATION  -Growth ceased i decapitation shoot A   - when agar block was placed on stump of shoot B in which growth had stopped growth resumed  -When mica sheet was placed on stump of shoot C in which growth had stopped, growth did not resume   Conclusion   This shows that a chemical substance or auxin was produced at the tip or apical cell of te shoot, which is responsible for growth of the soot","marks":"5","difficulty":"3"},{"id":"theory>Biology>2001>PART I>4>c>i","subject":"Biology","year":"2001","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Name two plant hormones, other than auxins.","images":[],"marking_scheme":"- Cytokinins   - Ethylene  - Formin   - Gibberellin  (any other correct hormones can named)","marks":"2","difficulty":"1"},{"id":"theory>Biology>2001>PART I>4>c>ii","subject":"Biology","year":"2001","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM","question":"Give two examples of tropism","images":[],"marking_scheme":"- Geotropism  - Hydrotropism  - Phototropism  - Chemotropism  - Thermotropism e.t.c","marks":"2","difficulty":"1"},{"id":"theory>Biology>2001>PART II>5>a","subject":"Biology","year":"2001","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"What is an ecosystem?","images":[],"marking_scheme":"An ecosystem: is a natural unit in which there is an interaction between all living organism/biotic factor and non-living  organism/abotic factor with an environment/habitat","marks":"4","difficulty":"1"},{"id":"theory>Biology>2001>PART II>5>b","subject":"Biology","year":"2001","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS","question":"Name two abiotic factor each which affects plants and animals in terrestrial habitat","images":[],"marking_scheme":"- Water/rainfal  - Temperature   - sunlight  - Wind  - pH. e.t.c","marks":"3","difficulty":"2"},{"id":"theory>Biology>2001>PART II>5>c","subject":"Biology","year":"2001","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS","question":"Describe the effect of three abiotic factors on a named plant and an animal in the habitat mentioned in (b) above","images":[],"marking_scheme":"1. Temperature  -High temperature : leads to high transpiration rate in plants and can lead to aestivation in animals.  -Lead to high rate of metabolism in living organism (Plants or animals)  -Leads to high rate of decay of organic matter  -A higher rate of growth and shorter lenght of life cycle in some organism  -At low temperature: plants roots absorb water at slower rates, there is also reduction in rate of transpiration and metabolism  - At low temperature animals may hibernate.  2. Rainfall  - Make water available to organism(plant and animals).  - Quantity of rainfall determines types of vegetation in a habitat   -Vegetation in turn influence types of animals that will live there.  - Rainfall/splash/Flood may dislodge organism.  -Rainfall increases relative humidity which may affect the rate of transpiration and perspiration in plants and animals respectively  - May form puddles/ ponds thereby creating habitats/ breeding grounds for certain terrestial organisms.  3. Wind   - Steady wind increase rate of evaporation/Transporation or even dessication in animals   - strong winds cause soil erosion which affect living organism  - Aids pollution  -strong winds breaks off branches of trees and forces animals out of cover  4. Light/sunlight  - intensity of sunlight affects plants by affecting rates of photosynthesis  -Affect the rate of transpiration /stomata opening  -Adequate sunlight promotes growth of many plant species  - It affect the distribution of organism in habitat  -Light affects the vision and movement   5. pH  - Increased acidity or alkalinity affects plants and animals health  - It  causes delay of germination in some seeds   -it also enhances germination in some seeds  - it affects plant and animals distribution","marks":"4","difficulty":"3"},{"id":"theory>Biology>2001>PART II>6>a>i","subject":"Biology","year":"2001","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING","question":"Name two types of competition","images":[],"marking_scheme":"- inter-specific competiton.  - intra-specific competition","marks":"3","difficulty":"2"},{"id":"theory>Biology>2001>PART II>6>a>ii","subject":"Biology","year":"2001","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING","question":"State four factors that bring about competition among organisms.","images":[],"marking_scheme":"- Food shortage/ scarcity  - Overpopulation  - Reduced number of mates   - Scarcity of water   - Unfavourable condition/climate.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2001>PART II>6>b","subject":"Biology","year":"2001","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION","question":"Outline the relationship between competition and succession.","images":[],"marking_scheme":"- competition leads to death of weak organism(and survival of the fiitest)  - competition give rise to succession  - change are brought about by replacement of old species by new species(i.e competiton)  - New species better adapt than old ones; new species utilizes components of old ones leading to a new stable community which leads to succession","marks":"4","difficulty":"2"},{"id":"theory>Biology>2001>PART II>6>c>i","subject":"Biology","year":"2001","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Explain briefly darwin's theory of natural selection","images":[],"marking_scheme":"- living organism produce more offspring than can survive  - Due to overproduction of offspring there is constant struggle or competition for existence among them  - some organism are well adapted to survive than others  -The well adapted ones will transmit such variation or traits to their ofspring  - those with poor adations will die off or become progressively less productive  - An accumulation of favourable variation will be lead to divergence of spread from orignal stock.  -Resulting i the formation of new species.","marks":"4","difficulty":"3"},{"id":"theory>Biology>2001>PART II>6>c>ii","subject":"Biology","year":"2001","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"List five evidence to support the occurance of evolution.","images":[],"marking_scheme":"- Evience of comparative anatomy  - Evidence from fossil record  - Evidence of estgial organs   - Evidence from cytology e.g DNA  - Embryological evidence","marks":"4","difficulty":"2"}];